import{_ as o,o as r,c as a,ag as t}from"./chunks/framework.BDsNeyd8.js";const h=JSON.parse('{"title":"Changelog","description":"","frontmatter":{"title":"Changelog","nav_order":4},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":1776625006000}'),d={name:"changelog.md"};function c(i,e,n,s,l,g){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to mimi.js are documented here.<br> Format follows <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>. Versions follow <a href="https://semver.org/" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><hr><h2 id="unreleased-—-v2-1-0" tabindex="-1">[Unreleased] — v2.1.0 <a class="header-anchor" href="#unreleased-—-v2-1-0" aria-label="Permalink to &quot;[Unreleased] — v2.1.0&quot;">​</a></h2><blockquote><p>Production-readiness upgrade. All changes are backward-compatible.</p></blockquote><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li><strong>Radix trie router</strong> via <code>find-my-way</code> — replaces linear layer scan. 50-route throughput goes from 43k req/s to ~90k req/s, matching Fastify. Route lookup is now O(k) on URL depth, not O(n) on route count.</li><li><strong>URL parsed once per request</strong> — <code>req.path</code> and <code>req.query</code> now memoize on first access instead of calling <code>new URL()</code> on every read. Eliminates ~86k allocations/second under load.</li><li><strong>Logger replaced</strong> — winston → pino. 7× faster structured logging, −6 MB RSS per process.</li><li><strong>Heavyweight deps moved to peer</strong> — <code>mongoose</code>, <code>sequelize</code>, <code>sqlite3</code>, <code>bcrypt</code> are now optional peer dependencies. Applications that don&#39;t use database features save 20+ MB RSS per process.</li></ul><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ul><li><code>app.setErrorHandler(fn)</code> — register a global error handler that intercepts all <code>next(err)</code> calls before the default 500 response.</li><li><code>app.addHook(name, fn)</code> — lifecycle hooks at 7 named points: <code>onRequest</code>, <code>preParsing</code>, <code>preValidation</code>, <code>preHandler</code>, <code>onSend</code>, <code>onResponse</code>, <code>onError</code>.</li><li><code>app.close([timeoutMs])</code> — graceful shutdown: stops accepting connections, drains in-flight requests, fires <code>onClose</code> hooks.</li><li><code>validate(targets)</code> — request validation middleware factory. Validates <code>body</code>, <code>params</code>, <code>query</code> against any schema adapter.</li><li>Built-in <strong>Zod adapter</strong> — <code>validate({ body: z.object({...}) })</code> with structured 400 responses.</li><li><code>setAdapter(adapter)</code> — swap the validation backend (Zod, Valibot, Joi, etc.) globally.</li><li><code>rateLimit(options)</code> — token-bucket rate limiter with per-IP tracking and <code>X-RateLimit-*</code> headers.</li><li><code>RequestContext</code> — per-request context object (<code>ctx</code>) with typed <code>body</code>, <code>params</code>, <code>query</code>, <code>store</code>, and response helpers.</li><li><strong>Ctx-style handlers</strong> — <code>app.get(&#39;/path&#39;, async (ctx) =&gt; { ctx.json(...) })</code> as an alternative to <code>(req, res, next)</code>.</li></ul><h3 id="developer-experience" tabindex="-1">Developer Experience <a class="header-anchor" href="#developer-experience" aria-label="Permalink to &quot;Developer Experience&quot;">​</a></h3><ul><li><strong>vitest</strong> test infrastructure with V8 coverage.</li><li>All new APIs exported from the main entry point with full TypeScript declarations.</li><li>Graceful install-hint errors when optional peer deps are missing.</li></ul><hr><h2 id="_2-0-0-—-2024" tabindex="-1">[2.0.0] — 2024 <a class="header-anchor" href="#_2-0-0-—-2024" aria-label="Permalink to &quot;[2.0.0] — 2024&quot;">​</a></h2><h3 id="breaking-changes" tabindex="-1">Breaking Changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking Changes&quot;">​</a></h3><ul><li>Full TypeScript rewrite. The package now ships compiled <code>.js</code> + <code>.d.ts</code> declarations from a <code>src/</code> TypeScript source tree.</li><li><code>main</code> entry changed from <code>lib/index.js</code> to <code>dist/index.js</code>.</li><li><code>mimi()</code> now returns a <code>MimiApp</code> typed interface.</li></ul><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Custom HTTP router</strong> — <code>Router</code> class with <code>Layer</code>/<code>Route</code> internals. Express-compatible <code>app.get/post/put/patch/delete/head/options/all</code> API.</li><li><strong>Prototype-augmented <code>req</code>/<code>res</code></strong> — <code>req.params</code>, <code>req.query</code>, <code>req.body</code>, <code>req.path</code>, <code>req.hostname</code>, <code>req.ip</code>, <code>req.locals</code>, <code>req.get()</code>, <code>req.is()</code>. <code>res.status()</code>, <code>res.json()</code>, <code>res.send()</code>, <code>res.redirect()</code>, <code>res.sendStatus()</code>, <code>res.set()</code>, <code>res.type()</code>.</li><li><strong>Body parsing</strong> — <code>json()</code>, <code>urlencoded()</code>, <code>customParser</code> (raw-body based).</li><li><strong>CORS middleware</strong> — <code>cors()</code> with origin function, credentials, maxAge.</li><li><strong>Security headers</strong> — <code>security()</code> sets CSP, X-Frame-Options, X-Content-Type-Options, X-XSS-Protection, X-DNS-Prefetch-Control.</li><li><strong>Static file serving</strong> — <code>serveStatic()</code>.</li><li><strong>Structured logging</strong> — <code>requestLogger</code> middleware, <code>logger</code> instance (winston → pino in v2.1).</li><li><strong>JWT auth</strong> — <code>generateToken</code>, <code>verifyToken</code>, <code>authMiddleware</code>.</li><li><strong>Password hashing</strong> — <code>hashPassword</code>, <code>comparePassword</code> (bcrypt).</li><li><strong>MongoDB adapter</strong> — <code>mongodbManager</code> singleton.</li><li><strong>SQLite adapter</strong> — <code>SQLiteManager</code> class (Sequelize + sqlite3).</li><li><strong>Swagger UI</strong> — <code>setupSwagger(app, options)</code> serves <code>/api-docs</code> from JSDoc annotations.</li><li><strong>Auto route loader</strong> — scans <code>./routes/*.js</code> at startup and mounts each file.</li><li><strong>Plugin system</strong> — <code>app.register(plugin, options)</code> with async support.</li><li><strong><code>async</code> handler support</strong> — errors from async handlers automatically forwarded to <code>next</code>.</li><li>Full TypeScript declarations for all exports.</li></ul><hr><h2 id="_1-x-—-2023–2024" tabindex="-1">[1.x] — 2023–2024 <a class="header-anchor" href="#_1-x-—-2023–2024" aria-label="Permalink to &quot;[1.x] — 2023–2024&quot;">​</a></h2><p>The original JavaScript implementation (<code>lib/</code> directory).</p><h3 id="key-features-in-v1" tabindex="-1">Key features in v1 <a class="header-anchor" href="#key-features-in-v1" aria-label="Permalink to &quot;Key features in v1&quot;">​</a></h3><ul><li><code>mimi()</code> factory wrapping Express with pre-configured middleware</li><li>JWT + bcrypt auth utilities</li><li>MongoDB and SQLite wrappers</li><li>Auto-route loading from <code>./routes/</code></li><li>express-jsdoc-swagger integration</li><li>Winston request logger</li></ul><hr><h2 id="versioning-policy" tabindex="-1">Versioning Policy <a class="header-anchor" href="#versioning-policy" aria-label="Permalink to &quot;Versioning Policy&quot;">​</a></h2><ul><li><strong>Patch</strong> (<code>2.x.Y</code>) — bug fixes, performance improvements, documentation</li><li><strong>Minor</strong> (<code>2.Y.0</code>) — new features, backward-compatible</li><li><strong>Major</strong> (<code>X.0.0</code>) — breaking API changes, announced in advance</li></ul>',25)])])}const u=o(d,[["render",c]]);export{h as __pageData,u as default};
